@app.route('/validate-redirect')
def validate_redirect():
    """Validate a redirect URI against a domain"""
    redirect_uri = request.args.get('redirect_uri')
    domain = request.args.get('domain')
    
    if not redirect_uri or not domain:
        return jsonify({'error': 'Missing redirect_uri or domain parameter'}), 400
    
    is_valid = validate_redirect_uri(redirect_uri, domain)
    
    return jsonify({
        'redirect_uri': redirect_uri,
        'domain': domain,
        'valid': is_valid
    })


